package format

import (
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for
// terraform plan, showing only resource-level changes without attribute-level
// detail.
type CompactDiffFormatter struct{}

// Format produces a compact summary of the plan's changes grouped by action type.
//
// The output includes one line per resource change in the format:
//   [action] resource_type.name
//
// Resources are grouped by action type (create, update, delete, replace) and
// a summary of change counts is shown at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group resources by action
	changes := &changeGroup{
		creates:  []string{},
		updates:  []string{},
		deletes:  []string{},
		replaces: []string{},
		noOps:    []string{},
		reads:    []string{},
		forgets:  []string{},
		other:    []string{},
	}

	for _, rc := range plan.Changes.Resources {
		// Skip deposed resources
		if rc.DeposedKey != states.NotDeposed {
			continue
		}

		addr := rc.Addr.String()

		switch rc.Action {
		case plans.Create:
			changes.creates = append(changes.creates, addr)
		case plans.Update:
			changes.updates = append(changes.updates, addr)
		case plans.Delete:
			changes.deletes = append(changes.deletes, addr)
		case plans.DeleteThenCreate, plans.CreateThenDelete:
			changes.replaces = append(changes.replaces, addr)
		case plans.NoOp:
			changes.noOps = append(changes.noOps, addr)
		case plans.Read:
			changes.reads = append(changes.reads, addr)
		case plans.Forget:
			changes.forgets = append(changes.forgets, addr)
		default:
			changes.other = append(changes.other, addr)
		}
	}

	// Sort all lists for consistent output
	sort.Strings(changes.creates)
	sort.Strings(changes.updates)
	sort.Strings(changes.deletes)
	sort.Strings(changes.replaces)
	sort.Strings(changes.noOps)
	sort.Strings(changes.reads)
	sort.Strings(changes.forgets)
	sort.Strings(changes.other)

	// Build output
	var buf strings.Builder

	// Output grouped changes
	if len(changes.creates) > 0 {
		buf.WriteString("# Resources to create\n")
		for _, addr := range changes.creates {
			fmt.Fprintf(&buf, "  + %s\n", addr)
		}
		buf.WriteString("\n")
	}

	if len(changes.updates) > 0 {
		buf.WriteString("# Resources to update\n")
		for _, addr := range changes.updates {
			fmt.Fprintf(&buf, "  ~ %s\n", addr)
		}
		buf.WriteString("\n")
	}

	if len(changes.replaces) > 0 {
		buf.WriteString("# Resources to replace\n")
		for _, addr := range changes.replaces {
			fmt.Fprintf(&buf, "  ±/∓ %s\n", addr)
		}
		buf.WriteString("\n")
	}

	if len(changes.deletes) > 0 {
		buf.WriteString("# Resources to delete\n")
		for _, addr := range changes.deletes {
			fmt.Fprintf(&buf, "  - %s\n", addr)
		}
		buf.WriteString("\n")
	}

	if len(changes.reads) > 0 {
		buf.WriteString("# Resources to read\n")
		for _, addr := range changes.reads {
			fmt.Fprintf(&buf, "  <- %s\n", addr)
		}
		buf.WriteString("\n")
	}

	if len(changes.forgets) > 0 {
		buf.WriteString("# Resources to forget\n")
		for _, addr := range changes.forgets {
			fmt.Fprintf(&buf, "  . %s\n", addr)
		}
		buf.WriteString("\n")
	}

	// Output summary
	buf.WriteString("Summary:\n")
	fmt.Fprintf(&buf, "  Create:  %d\n", len(changes.creates))
	fmt.Fprintf(&buf, "  Update:  %d\n", len(changes.updates))
	fmt.Fprintf(&buf, "  Replace: %d\n", len(changes.replaces))
	fmt.Fprintf(&buf, "  Delete:  %d\n", len(changes.deletes))
	fmt.Fprintf(&buf, "  Read:    %d\n", len(changes.reads))
	fmt.Fprintf(&buf, "  Forget:  %d\n", len(changes.forgets))

	return buf.String()
}

type changeGroup struct {
	creates  []string
	updates  []string
	deletes  []string
	replaces []string
	noOps    []string
	reads    []string
	forgets  []string
	other    []string
}

