package format

import (
	"strings"
	"testing"

	"github.com/google/go-cmp/cmp"
	"github.com/zclconf/go-cty/cty"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := map[string]struct {
		plan *plans.Plan
		want string
	}{
		"nil plan": {
			plan: nil,
			want: "",
		},
		"empty plan": {
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Create,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to create
  + aws_instance.example

Summary:
  Create:  1
  Update:  0
  Replace: 0
  Delete:  0
  Read:    0
  Forget:  0
`,
		},
		"multiple changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Create,
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "main",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Update,
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_key_pair",
										Name: "old",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Delete,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to create
  + aws_instance.example

# Resources to update
  ~ aws_security_group.main

# Resources to delete
  - aws_key_pair.old

Summary:
  Create:  1
  Update:  1
  Replace: 0
  Delete:  1
  Read:    0
  Forget:  0
`,
		},
		"replace action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.DeleteThenCreate,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to replace
  ±/∓ aws_instance.example

Summary:
  Create:  0
  Update:  0
  Replace: 1
  Delete:  0
  Read:    0
  Forget:  0
`,
		},
		"read action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.DataResourceMode,
										Type: "aws_ami",
										Name: "ubuntu",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Read,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to read
  <- data.aws_ami.ubuntu

Summary:
  Create:  0
  Update:  0
  Replace: 0
  Delete:  0
  Read:    1
  Forget:  0
`,
		},
		"forget action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "forgotten",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Forget,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to forget
  . aws_instance.forgotten

Summary:
  Create:  0
  Update:  0
  Replace: 0
  Delete:  0
  Read:    0
  Forget:  1
`,
		},
	}

	formatter := &CompactDiffFormatter{}
	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(tc.plan, &schemarepo.Schemas{})
			if diff := cmp.Diff(tc.want, got); diff != "" {
				t.Errorf("Format() mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

func TestCompactDiffFormatter_Sorting(t *testing.T) {
	// Test that resources are sorted within their action groups
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "zebra",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "apple",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "middle",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, &schemarepo.Schemas{})

	// Verify that apple comes before middle, which comes before zebra
	appleIdx := strings.Index(got, "aws_instance.apple")
	middleIdx := strings.Index(got, "aws_instance.middle")
	zebraIdx := strings.Index(got, "aws_instance.zebra")

	if appleIdx == -1 || middleIdx == -1 || zebraIdx == -1 {
		t.Fatalf("Expected all resources to be in output: %s", got)
	}

	if appleIdx > middleIdx || middleIdx > zebraIdx {
		t.Errorf("Resources not sorted correctly. got:\n%s", got)
	}
}

func TestCompactDiffFormatter_DeposedResources(t *testing.T) {
	// Test that deposed resources are skipped
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "example",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "deposed",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Delete,
					DeposedKey: states.DeposedKey("0000000000000001"), // non-NotDeposed
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, &schemarepo.Schemas{})

	// Verify that deposed resource is not in output
	if strings.Contains(got, "aws_instance.deposed") {
		t.Errorf("Deposed resource should not appear in output:\n%s", got)
	}

	// Verify that non-deposed resource is in output
	if !strings.Contains(got, "aws_instance.example") {
		t.Errorf("Non-deposed resource should appear in output:\n%s", got)
	}
}

