// Copyright (c) HashiCorp, Inc.
// SPDX-License-Identifier: BUSL-1.1

package format

import (
	"strings"
	"testing"

	"github.com/google/go-cmp/cmp"
	"github.com/zclconf/go-cty/cty"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := map[string]struct {
		plan *plans.Plan
		want string
	}{
		"nil plan": {
			plan: nil,
			want: "",
		},
		"empty plan": {
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Create,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to create
  + aws_instance.example

Summary:
  Create:  1
  Update:  0
  Replace: 0
  Delete:  0
  Read:    0
  Forget:  0
`,
		},
		"multiple changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Create,
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "main",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Update,
							DeposedKey: states.NotDeposed,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_key_pair",
										Name: "old",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Delete,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to create
  + aws_instance.example

# Resources to update
  ~ aws_security_group.main

# Resources to delete
  - aws_key_pair.old

Summary:
  Create:  1
  Update:  1
  Replace: 0
  Delete:  1
  Read:    0
  Forget:  0
`,
		},
		"replace action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.DeleteThenCreate,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to replace
  ±/∓ aws_instance.example

Summary:
  Create:  0
  Update:  0
  Replace: 1
  Delete:  0
  Read:    0
  Forget:  0
`,
		},
		"read action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.DataResourceMode,
										Type: "aws_ami",
										Name: "ubuntu",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Read,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to read
  <- data.aws_ami.ubuntu

Summary:
  Create:  0
  Update:  0
  Replace: 0
  Delete:  0
  Read:    1
  Forget:  0
`,
		},
		"forget action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "forgotten",
									},
									Key: addrs.NoKey,
								},
							},
							Action:     plans.Forget,
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			want: `# Resources to forget
  . aws_instance.forgotten

Summary:
  Create:  0
  Update:  0
  Replace: 0
  Delete:  0
  Read:    0
  Forget:  1
`,
		},
	}

	formatter := &CompactDiffFormatter{}
	for name, tc := range tests {
